/// <summary>
/// This class contain the logic for creation of Inventory journal.
/// </summary>
internal final class ETGTrackingNumInventoryJournalCreate
{
    ETGConversionToInventoryTable etgConversionToInventory;
    Set assetTableList;

}

Method.Source:
/// <summary>
/// This is an instance
/// </summary>
/// <returns>ETGTrackingNumInventoryJournalCreate.</returns>
public static ETGTrackingNumInventoryJournalCreate constrcuct()
{
    return new ETGTrackingNumInventoryJournalCreate();
}

/// <summary>
/// This method will return the ETGConversionToInventory table.
/// </summary>
/// <param name = "_etgConversionToInventoryTable">ETGConversionToInventoryTable.</param>
/// <returns>ETGConversionToInventory.</returns>
public ETGConversionToInventoryTable parmETGConvertionToTable(ETGConversionToInventoryTable _etgConversionToInventoryTable
    = etgConversionToInventory)
{
    etgConversionToInventory = _etgConversionToInventoryTable;
    return etgConversionToInventory;
}

/// <summary>
///In this method returning the list of records in AssetTable.
/// </summary>
/// <param name = "_assetTableList">AssetTable.</param>
/// <returns>AssetTable.</returns>
public Set parmListOfRecords(Set _assetTableList = assetTableList)
{
    assetTableList = _assetTableList;
    return assetTableList;
}

/// <summary>
/// Class entry point. The system will call this method when a designated menu
/// is selected or when execution starts and this class is set as the startup class.
/// </summary>
/// <param name = "args">The specified arguments.</param>
public static void main(Args args)
{
    if(args && args.parmObject())
    {
        ETGTrackingNumInventoryJournalCreate inventoryJournalCreator = ETGTrackingNumInventoryJournalCreate::constrcuct();
        inventoryJournalCreator.parmListOfRecords(args.parmObject());

        inventoryJournalCreator.parmETGConvertionToTable(args.record());
        ttsbegin;
        inventoryJournalCreator.journalLineCreation(inventoryJournalCreator.journalHeaderCreation());
        ttscommit;
    }
}

/// <summary>
/// This method contain the creation of Inventory Journal Header.
/// </summary>
/// <returns>InventJournalTable.</returns>
public InventJournalTable journalHeaderCreation()
{
    InventJournalTable              inventJournalTable;
    InventJournalNameId             inventJournalName;

    inventJournalTable.clear();
    inventJournalName =  InventJournalName::standardJournalName(InventJournalType::LossProfit);
    inventJournalTable.initFromInventJournalName(InventJournalName::find(InventParameters::find().ETGJournalName));
    inventJournalTable.ETGConversionToInventory = NoYes::Yes;
    inventJournalTable.insert();
    return InventJournalTable;
}

/// <summary>
/// This method contain the creation of Inventory Journal Lines.
/// </summary>
/// <param name = "inventJournalTable">InventJournalTable.</param>
public void journalLineCreation(InventJournalTable inventJournalTable)
{
    InventJournalTrans              inventJournalTrans;
    InventDim                       inventDim;
    AssetTable                      assetTable;
    SetEnumerator se = assetTableList.getEnumerator();

    while (se.moveNext())
    {
        assetTable                      = se.current();
        inventJournalTrans.clear();
        inventJournalTrans.initFromInventJournalTable(inventJournalTable);
        inventJournalTrans.TransDate    = etgConversionToInventory.TransDate;
        inventJournalTrans.ItemId       = etgConversionToInventory.ItemNumber;
        inventJournalTrans.initFromInventTable(InventTable::find(etgConversionToInventory.ItemNumber));
        inventJournalTrans.Qty          = assetTable.Quantity;
        inventDim.InventSiteId          = etgConversionToInventory.InventSiteId;
        inventDim.InventLocationId      = etgConversionToInventory.InventLocationId;
        inventDim.wMSLocationId         = etgConversionToInventory.wMSLocationId;
        inventDim.InventStyleId         = etgConversionToInventory.Brand;
        inventDim.InventColorId         = etgConversionToInventory.Origin;
        inventDim.InventSizeId          = etgConversionToInventory.Size;
        inventDim.inventBatchId         = etgConversionToInventory.InventBatchId;
        inventDim.configId              = etgConversionToInventory.Grade;
        inventJournalTrans.InventDimId  = inventDim::findOrCreate(inventDim).inventDimId;
        inventJournalTrans.ETGAssetId   = assetTable.AssetId;
        inventJournalTrans.insert();
    }
    info(strFmt("@ETG_New:InventJournalCreation", inventJournalTable.JournalId));

}
